// ─────────────────────────────────────────────
// Filter + Build Flex Alert
// หา rows ที่: acknowledged=FALSE, ค้างนาน 60+ นาที, แจ้งไม่เกิน 3 ครั้ง
// ส่ง Flex Message Carousel — แต่ละการ์ดมีปุ่ม ✅ ตอบแล้ว (postback)
// เมื่อ SK TEAM tap → webhook รับ postback → mark acknowledged=TRUE อัตโนมัติ
// ─────────────────────────────────────────────
const now          = Date.now();
const BKK          = 7 * 3600 * 1000;
const bkk          = new Date(now + BKK);
const timeStr      = bkk.toISOString().replace('T', ' ').substring(0, 16);

const THRESHOLD_MS = 60 * 60 * 1000;   // 1 ชั่วโมง — ยังไม่ตอบถึงจะ escalate
const MAX_ALERTS   = 3;                // แจ้งสูงสุด 3 รอบ (ทุก 15 นาที = 45 นาที)
const MAX_AGE_MS   = 8 * 3600 * 1000;  // เกิน 8 ชม. หยุดแจ้งอัตโนมัติ

const rows = $input.all().map(r => r.json);

const pending = rows.filter(row => {
  if (!row.row_id) return false;
  if ((row.acknowledged || 'FALSE').toUpperCase() === 'TRUE') return false;
  if (parseInt(row.alert_count || 0) >= MAX_ALERTS) return false;
  const received = new Date(row.received_at).getTime();
  const elapsed  = now - received;
  if (isNaN(elapsed) || elapsed < THRESHOLD_MS) return false;
  if (elapsed > MAX_AGE_MS) return false;
  return true;
});

if (pending.length === 0) return [];

// ── สร้าง Flex Carousel — 1 การ์ดต่อ 1 ข้อความค้าง ──
const bubbles = pending.map(row => {
  const elapsedMin = Math.round((now - new Date(row.received_at).getTime()) / 60000);
  const alertRound = parseInt(row.alert_count || 0) + 1;
  const isUrgent   = alertRound >= MAX_ALERTS;
  const headerBg   = isUrgent ? '#B71C1C' : '#E53935';
  const src        = row.group_name ? `📢 ${row.group_name}` : '💬 DM ส่วนตัว';
  const msgPreview = (row.message_text || '').substring(0, 80);

  return {
    type: 'bubble', size: 'kilo',
    header: {
      type: 'box', layout: 'vertical',
      backgroundColor: headerBg, paddingAll: '12px',
      contents: [{
        type: 'text',
        text: `⏰ รอบที่ ${alertRound}/${MAX_ALERTS} — ยังไม่ตอบ!`,
        color: '#ffffff', weight: 'bold', size: 'sm'
      }]
    },
    body: {
      type: 'box', layout: 'vertical', spacing: 'sm', paddingAll: '14px',
      contents: [
        { type: 'text', text: src, weight: 'bold', size: 'md', wrap: true },
        { type: 'text', text: `👤 ${row.user_name || 'ไม่ทราบชื่อ'}`, size: 'sm', color: '#555555' },
        { type: 'text', text: `💬 ${msgPreview}`, size: 'sm', wrap: true, color: '#333333' },
        { type: 'separator', margin: 'md' },
        { type: 'text', text: `⏱ รอมา ${elapsedMin} นาที`, size: 'sm', color: headerBg, weight: 'bold' }
      ]
    },
    footer: {
      type: 'box', layout: 'vertical', paddingAll: '10px',
      contents: [{
        type: 'button', height: 'sm', style: 'primary', color: '#34a853',
        action: {
          type: 'postback',
          label: '✅ ตอบแล้ว',
          data: `action=ack&row_id=${row.row_id}`,
          displayText: `✅ ตอบแล้ว (${row.user_name || 'ลูกค้า'})`
        }
      }]
    }
  };
});

const flexPayload = JSON.stringify({
  to: 'C40b37d81f4e199a7b7357537166a1efd',
  messages: [{
    type: 'flex',
    altText: `⏰ ${pending.length} ข้อความรอตอบ (ค้างนาน 1+ ชม.) — กด ✅ ตอบแล้ว`,
    contents: { type: 'carousel', contents: bubbles }
  }]
});

return [{ json: { flexPayload, pendingRows: pending, count: pending.length } }];

// ขยาย pendingRows array เป็น items แยกกัน
// เพื่อให้ Google Sheets node update ทีละ row
const rows = $json.pendingRows || [];
return rows.map(row => ({
  json: {
    row_id:        row.row_id,
    alert_count:   String(parseInt(row.alert_count || 0) + 1),
    last_alert_at: new Date().toISOString()
  }
}));
